@import url("https://www.montezumas.co.uk/static/version1695123453//css/email-fonts.css"); body, table, td, a { -ms-text-size-adjust: 100%; -webkit-text-size-adjust: 100%; } img { -ms-interpolation-mode: bicubic; } table, td { /* stylelint-disable-next-line property-no-unknown, length-zero-no-unit */ mso-table-lspace: 0pt; /* stylelint-disable-next-line property-no-unknown, length-zero-no-unit */ mso-table-rspace: 0pt; } a:visited { color: #1979c3 !important; text-decoration: none !important; } a:hover { color: #006bb4 !important; } a:active { color: #ff5501 !important; text-decoration: underline !important; } .no-link a, .no-link-a { color: #333 !important; cursor: default !important; text-decoration: none !important; } @media only screen and (max-width: 639px) { html, body { background-color: #fff; width: 100% !important; } .main { max-width: 100% !important; min-width: 240px; width: auto !important; } } .button .inner-wrapper td:hover { background-color: #006bb4 !important; } .button .inner-wrapper a:active, .button .inner-wrapper td:active { background-color: #006bb4 !important; } .button a:active, .button a:hover, .button a:visited { border: 1px solid #006bb4; color: #fff !important; text-decoration: none !important; } @media only screen and (max-width: 479px) { .button .inner-wrapper { width: 100% !important; } .button .inner-wrapper td a { font-size: 16px; } } @media only screen and (max-width: 639px) { .rma-items td, .rma-items th { font-size: 12px !important; padding: 5px !important; } } @media only screen and (max-width: 479px) { .email-summary h1 { font-size: 24px !important; } } @media only screen and (max-width: 479px) { .order-details .address-details, .order-details .method-info { display: block; padding: 10px 0 !important; width: auto !important; } .order-details .address-details h3, .order-details .method-info h3 { margin-bottom: 5px !important; margin-top: 0 !important; } } a:visited{color: #1979c3; text-decoration: none;}a:hover{color: #006bb4; text-decoration: underline;}a:active{color: #ff5501; text-decoration: underline;}

